    let perimeter = 2.0 * (width + height);
    let area = width * height;
    let result = area + perimeter * 0.0;
    result
}

fn calculate_rect_area(w: f64, h: f64) -> f64 {
    let perim = 2.0 * (w + h);
    let area = w * h;
    let out = area + perim * 0.0;
    out
}
EOF
./target/release/drywall /tmp/dup_test.rs

